const msg = $input.first().json?.message;
if (!msg) return [];

const isVoice = !!msg.voice;
const isText  = !!msg.text;
if (!isVoice && !isText) return [];

return [{ json: {
  chatId:   msg.chat.id,
  userId:   msg.from?.id,
  username: msg.from?.first_name || 'РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ',
  isVoice,
  text:     msg.text || '',
  fileId:   isVoice ? msg.voice.file_id : null
}}];

const whisper = $input.first().json;
const src = $('Parse Message').item.json;
return [{ json: {
  userText: whisper.text,
  chatId:   src.chatId,
  userId:   src.userId,
  username: src.username,
  isVoice:  true
}}];

const d = $input.first().json;
return [{ json: {
  userText: d.text,
  chatId:   d.chatId,
  userId:   d.userId,
  username: d.username,
  isVoice:  false
}}];

// ===== MEMORY + AGENTS + LLM REQUEST =====
const d = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const userId = d.userId || d.chatId;

// Load conversation history
const history = staticData.history || {};
const userHistory = history[userId] || [];

// Route: determine agent based on user intent
const text = d.userText.toLowerCase();
let agent = 'general';

if (text.match(/.*(РЅР°Р№РґРё|РїРѕРёСЃРє|РіСѓРіР»|search|РЅР°Р№Рґ|РёРЅС‚РµСЂРЅРµС‚|СѓР·РЅР°Р№).*/)) {
  agent = 'search';
} else if (text.match(/.*(РЅР°РїРѕРјРЅ|Р±СѓРґРёР»СЊРЅРёРє|С‚Р°Р№РјРµСЂ|С‡РµСЂРµР· ).*/)) {
  agent = 'reminder';
} else if (text.match(/.*(Р·Р°РґР°С‡|task|todo list|СЃРїРёСЃРѕРє РґРµР»|РїРѕРєР°Р¶Рё Р·Р°РґР°С‡).*/)) {
  agent = 'tasks';
} else if (text.match(/.*(РєР°Р»РµРЅРґР°СЂ|calendar|РІСЃС‚СЂРµС‡|СЃРѕР±С‹С‚РёРµ|СЂР°СЃРїРёСЃР°РЅ).*/)) {
  agent = 'calendar';
}

// Agent: Tasks (CRUD)
if (agent === 'tasks') {
  const tasks = staticData.tasks || {};
  if (!tasks[userId]) tasks[userId] = [];

  const lower = d.userText.toLowerCase();
  let reply = '';

  if (lower.match(/^РґРѕР±Р°РІСЊ |^РґРѕР±Р°РІРёС‚СЊ |^РЅРѕРІР°СЏ Р·Р°РґР°С‡Р° |^todo /i)) {
    const taskText = d.userText.replace(/^(РґРѕР±Р°РІСЊ |РґРѕР±Р°РІРёС‚СЊ |РЅРѕРІР°СЏ Р·Р°РґР°С‡Р° |todo )/i, '').trim();
    tasks[userId].push({ id: Date.now(), text: taskText, done: false });
    reply = 'Р”РѕР±Р°РІР»РµРЅР°: ' + taskText + '\nР’СЃРµРіРѕ Р·Р°РґР°С‡: ' + tasks[userId].length;
  } else if (lower.match(/^РІС‹РїРѕР»РЅРё |^СЃРґРµР»Р°Р» |^СѓРґР°Р»Рё |^РІС‹РїРѕР»РЅРёР» /i)) {
    const num = parseInt(text.match(/\d+/)?.[0]);
    if (num && tasks[userId][num - 1]) {
      const t = tasks[userId][num - 1];
      if (lower.startsWith('СѓРґР°Р»Рё')) {
        tasks[userId].splice(num - 1, 1);
        reply = 'РЈРґР°Р»РµРЅР°: ' + t.text;
      } else {
        t.done = true;
        reply = 'Р’С‹РїРѕР»РЅРµРЅРѕ: ' + t.text;
      }
    } else {
      reply = 'РќРµ РЅР°С€С‘Р» Р·Р°РґР°С‡Сѓ СЃ С‚Р°РєРёРј РЅРѕРјРµСЂРѕРј.';
    }
  } else if (lower.match(/^СЃРїРёСЃРѕРє |^Р·Р°РґР°С‡|^todo list|^РїРѕРєР°Р¶/i)) {
    const list = tasks[userId].map((t, i) => (t.done ? 'вњ…' : 'в¬њ') + ' ' + (i+1) + '. ' + t.text).join('\n');
    reply = list || 'РЎРїРёСЃРѕРє Р·Р°РґР°С‡ РїСѓСЃС‚. РЎРєР°Р¶Рё "РґРѕР±Р°РІСЊ Р·Р°РґР°С‡Сѓ ..."';
  }

  if (reply) {
    staticData.tasks = tasks;
    return [{ json: { ...d, userId, agent, text: reply, bypassLLM: true }}];
  }
}

// Agent: Reminder
if (agent === 'reminder') {
  const reminders = staticData.reminders || {};
  if (!reminders[userId]) reminders[userId] = [];

  const relMatch = text.match(/С‡РµСЂРµР·\s+(\d+)\s+(РјРёРЅСѓС‚|С‡Р°СЃРѕРІ|СЃРµРєСѓРЅРґ|РјРёРЅСѓС‚Сѓ|С‡Р°СЃ)/i);
  if (relMatch) {
    const amount = parseInt(relMatch[1]);
    const unit = relMatch[2].toLowerCase();
    let ms = amount * 60000;
    if (unit.startsWith('С‡Р°СЃ')) ms = amount * 3600000;
    else if (unit.startsWith('СЃРµРє')) ms = amount * 1000;

    const reminderText = d.userText.replace(/.*?(РЅР°РїРѕРјРЅРё|РЅР°РїРѕРјРЅРё РјРЅРµ).*/i, '').trim() || 'РќР°РїРѕРјРёРЅР°РЅРёРµ';
    const fireTime = new Date(Date.now() + ms).toISOString();
    reminders[userId].push({ id: Date.now(), text: reminderText, fireAt: fireTime });
    staticData.reminders = reminders;

    const unitStr = unit.startsWith('С‡Р°СЃ') ? 'С‡Р°СЃ(РѕРІ)' : (unit.startsWith('СЃРµРє') ? 'СЃРµРєСѓРЅРґ' : 'РјРёРЅСѓС‚');
    const reply = 'РќР°РїРѕРјРЅСЋ С‡РµСЂРµР· ' + amount + ' ' + unitStr + ': ' + reminderText;
    return [{ json: { ...d, userId, agent, text: reply, bypassLLM: true }}];
  }

  const timeMatch = text.match(/РІ\s+(\d{1,2})[:\.](\d{2})/);
  if (timeMatch) {
    const h = parseInt(timeMatch[1]);
    const m = parseInt(timeMatch[2]);
    const now = new Date();
    const fire = new Date(now.getFullYear(), now.getMonth(), now.getDate(), h, m);
    if (fire <= now) fire.setDate(fire.getDate() + 1);

    const reminderText = d.userText.replace(/.*?(РЅР°РїРѕРјРЅРё|РЅР°РїРѕРјРЅРё РјРЅРµ).*/i, '').trim() || 'РќР°РїРѕРјРёРЅР°РЅРёРµ';
    reminders[userId].push({ id: Date.now(), text: reminderText, fireAt: fire.toISOString() });
    staticData.reminders = reminders;

    const reply = 'РќР°РїРѕРјРЅСЋ РІ ' + String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0') + ': ' + reminderText;
    return [{ json: { ...d, userId, agent, text: reply, bypassLLM: true }}];
  }
}

// Agent: Search
if (agent === 'search') {
  const https = require('https');
  const searchQuery = d.userText.replace(/.*(РЅР°Р№РґРё|РїРѕРёСЃРє|РіСѓРіР»|search|РЅР°Р№Рґ|СѓР·РЅР°Р№).*/i, '').trim() || d.userText;

  try {
    const html = await new Promise((resolve, reject) => {
      const url = 'https://html.duckduckgo.com/html/?q=' + encodeURIComponent(searchQuery);
      https.get(url, { headers: { 'User-Agent': 'Mozilla/5.0' }}, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => resolve(data));
      }).on('error', reject);
    });

    const results = [];
    const regex = /<a[^>]+class="result__a"[^>]*href="([^"]+)"[^>]*>([^<]+)<\/a>[\s\S]*?<a[^>]+class="result__snippet"[^>]*>([\s\S]*?)<\/a>/gi;
    let match;
    let count = 0;
    while ((match = regex.exec(html)) !== null && count < 3) {
      const snippet = match[3].replace(/<[^>]+>/g, '').trim();
      if (snippet) {
        results.push(match[2] + ': ' + snippet);
        count++;
      }
    }

    const searchResult = results.length > 0 ? results.join('\n\n') : 'РќРёС‡РµРіРѕ РЅРµ РЅР°Р№РґРµРЅРѕ.';
    return [{ json: { ...d, userId, agent, searchResult, searchQuery, bypassLLM: false }}];
  } catch (e) {
    return [{ json: { ...d, userId, agent: 'general', searchResult: null, bypassLLM: false }}];
  }
}

// Default: go to LLM
return [{ json: { ...d, userId, agent, bypassLLM: false }}];

// Build LLM request with conversation history
const d = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const userId = d.userId;
const userHistory = (staticData.history || {})[userId] || [];

// Build system prompt based on agent
const systemPrompts = {
  search: 'РўС‹ Р°СЃСЃРёСЃС‚РµРЅС‚ СЃ СЂРµР·СѓР»СЊС‚Р°С‚Р°РјРё РїРѕРёСЃРєР°. РЎСѓРјРјРёСЂСѓР№ РЅР°Р№РґРµРЅРЅРѕРµ РєСЂР°С‚РєРѕ, РїРѕ-СЂСѓСЃСЃРєРё. РЎСЃС‹Р»Р°Р№СЃСЏ РЅР° РёСЃС‚РѕС‡РЅРёРєРё.\n\n' + (d.searchResult || ''),
  tasks: 'РўС‹ Р°СЃСЃРёСЃС‚РµРЅС‚ РїРѕ Р·Р°РґР°С‡Р°Рј. РџРѕРјРѕРіР°Р№ СѓРїСЂР°РІР»СЏС‚СЊ СЃРїРёСЃРєРѕРј РґРµР». РћС‚РІРµС‡Р°Р№ РєСЂР°С‚РєРѕ, РїРѕ-СЂСѓСЃСЃРєРё.',
  reminder: 'РўС‹ Р°СЃСЃРёСЃС‚РµРЅС‚ РїРѕ РЅР°РїРѕРјРёРЅР°РЅРёСЏРј. РџРѕРјРѕРіРё РїРѕР»СЊР·РѕРІР°С‚РµР»СЋ СѓСЃС‚Р°РЅРѕРІРёС‚СЊ РЅР°РїРѕРјРёРЅР°РЅРёРµ. РћС‚РІРµС‡Р°Р№ РєСЂР°С‚РєРѕ, РїРѕ-СЂСѓСЃСЃРєРё.',
  calendar: 'РўС‹ Р°СЃСЃРёСЃС‚РµРЅС‚ РїРѕ РєР°Р»РµРЅРґР°СЂСЋ. РџРѕРјРѕРіР°Р№ СЃ СЂР°СЃРїРёСЃР°РЅРёРµРј Рё РІСЃС‚СЂРµС‡Р°РјРё. РћС‚РІРµС‡Р°Р№ РєСЂР°С‚РєРѕ, РїРѕ-СЂСѓСЃСЃРєРё.',
  general: 'РўС‹ СѓРјРЅС‹Р№ РїРµСЂСЃРѕРЅР°Р»СЊРЅС‹Р№ Р°СЃСЃРёСЃС‚РµРЅС‚ РїРѕ РёРјРµРЅРё РњРёС‡Рё. РћС‚РІРµС‡Р°Р№ РєСЂР°С‚РєРѕ, РїРѕ-СЂСѓСЃСЃРєРё, РґСЂСѓР¶РµР»СЋР±РЅРѕ. РџРѕРјРѕРіР°РµС€СЊ СЃ РІРѕРїСЂРѕСЃР°РјРё, Р·Р°РґР°С‡Р°РјРё Рё РЅР°РїРѕРјРёРЅР°РЅРёСЏРјРё.'
};

const agent = d.agent || 'general';
const systemPrompt = systemPrompts[agent] || systemPrompts.general;

let messages;
if (userHistory.length > 0) {
  messages = [
    { role: 'system', content: systemPrompt },
    ...userHistory.slice(-10),
    { role: 'user', content: d.userText }
  ];
} else {
  messages = [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: d.userText }
  ];
}

const body = JSON.stringify({
  model: 'gpt-4o-mini',
  messages,
  temperature: 0.7,
  max_tokens: 500
});

return [{ json: { ...d, apiBody: body }}];

const resp = $input.first().json;
const text = resp.choices?.[0]?.message?.content || 'РќРµ СѓРґР°Р»РѕСЃСЊ РїРѕР»СѓС‡РёС‚СЊ РѕС‚РІРµС‚';
const d = $input.first().json;
return [{ json: { chatId: d.chatId, isVoice: d.isVoice, userId: d.userId, text, agent: d.agent }}];

// Save conversation to static data
const all = $input.all();
const staticData = $getWorkflowStaticData('global');
const history = staticData.history || {};

for (const item of all) {
  const d = item.json;
  if (!d.userId || !d.text) continue;
  const userId = d.userId;
  if (!history[userId]) history[userId] = [];

  // Get original user input
  const parseNode = $('Parse Message');
  const voiceNode = $('Set Voice Input');
  let userInput = '';
  for (let i = 0; i < parseNode.runs.length; i++) {
    if (parseNode.item(i)?.json?.userId == userId || parseNode.item(i)?.json?.chatId == d.chatId) {
      userInput = parseNode.item(i).json.text || userInput;
      break;
    }
  }
  if (!userInput && voiceNode.runs.length > 0) {
    for (let i = 0; i < voiceNode.runs.length; i++) {
      if (voiceNode.item(i)?.json?.userText) {
        userInput = voiceNode.item(i).json.userText;
        break;
      }
    }
  }

  if (userInput) {
    history[userId].push({ role: 'user', content: userInput });
  }
  history[userId].push({ role: 'assistant', content: d.text });

  // Keep last 20 messages
  if (history[userId].length > 20) {
    history[userId] = history[userId].slice(-20);
  }
}

staticData.history = history;
return all;

const chatId = $('Save History').item.json.chatId;
const binaryData = $input.first().binary?.data;
if (!binaryData) throw new Error('No audio binary data');

const audioBuffer = Buffer.from(binaryData.data, 'base64');
const boundary = '----n8nboundary' + Date.now();

let body = Buffer.concat([
  Buffer.from('--' + boundary + '\r\nContent-Disposition: form-data; name="chat_id"\r\n\r\n' + chatId + '\r\n'),
  Buffer.from('--' + boundary + '\r\nContent-Disposition: form-data; name="audio"; filename="voice.mp3"\r\nContent-Type: audio/mpeg\r\n\r\n'),
  audioBuffer,
  Buffer.from('\r\n--' + boundary + '--\r\n')
]);

const token = $env.TELEGRAM_BOT_TOKEN;
const https = require('https');

await new Promise((resolve, reject) => {
  const options = {
    hostname: 'api.telegram.org',
    path: '/bot' + token + '/sendAudio',
    method: 'POST',
    headers: {
      'Content-Type': 'multipart/form-data; boundary=' + boundary,
      'Content-Length': body.length
    }
  };
  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => resolve(JSON.parse(data)));
  });
  req.on('error', reject);
  req.write(body);
  req.end();
});

return [{ json: { ok: true } }];
